#include <stdio.h>

int rev(int x){
    return (x % 10) * 10 + x / 10;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int A, B; scanf("%d %d", &A, &B);
        int revA = rev(A);
        int revB = rev(B);
        int maxA = A > revA ? A : revA;
        int minB = B < revB ? B : revB;
        if(maxA > minB) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

